import React, { useState } from 'react';
import main_page from '../css/main_page.module.css';

import Header from './components/Header';
import LeftMenu from './components/LeftMenu';
import DashboardContent from './components/DashboardContent';
import MyTasksContent from './components/MyTasksContent';


const MainPage = () => {
    const [activeMenuItem, setActiveMenuItem] = useState('dashboard');

    const handleMenuItemClick = (key) => {
        setActiveMenuItem(key);
        console.log(`Навігація до: ${key}`);
    };
    
    const handleLogout = () => {
    };

    const renderContent = () => {
        switch (activeMenuItem) {
            case 'dashboard':
                return <DashboardContent />;
            case 'my-task':
                return <MyTasksContent />;
            default:
                return <DashboardContent />;
        }
    };

    return (
        <>
            <Header /> 
            <div className={main_page.main_page}>
                <div className={main_page.menu}>
                    <LeftMenu 
                        activeItem={activeMenuItem}
                        onMenuItemClick={handleMenuItemClick}
                        onLogout={handleLogout}
                    />
                </div>
                <div className={main_page.content}>
                    {renderContent()}
                </div>
            </div>
        </>
    );
};

export default MainPage;
